// PropertyService MCP endpoints, derived from the protobuf package and service name.
const PropertyServiceMCPDefaultBasePath = "/freebusy/property/v1/propertyservice/mcp"

// PropertyServiceCompletionMap returns a map of "promptName:argName" → allowed
// values, built from enum_values declared in the proto MCP options.
func PropertyServiceCompletionMap() map[string][]string {
	m := map[string][]string{}
	m["add_unit:booking_mode"] = []string{"time_slot", "nightly"}
	return m
}

// ServePropertyServiceMCP creates an MCP server, registers the service tools, and
// starts serving using the configured transport (streamable-http, sse, or stdio).
// Uses the proto-derived BasePath. This is a blocking call.
func ServePropertyServiceMCP(ctx context.Context, srv PropertyServiceMCPServer, cfg *runtime.MCPServerConfig, opts ...runtime.Option) error {
	// Set the proto-derived path as the generated default
	cfg.GeneratedBasePath = PropertyServiceMCPDefaultBasePath

	// Wire completion handler for prompt arguments with enum_values.
	completionMap := PropertyServiceCompletionMap()
	if len(completionMap) > 0 {
		if cfg.ServerOptions == nil {
			cfg.ServerOptions = &mcp.ServerOptions{}
		}
		cfg.ServerOptions.CompletionHandler = runtime.CompletionHandlerFromEnums(completionMap)
	}

	// Forward the hosting server's unary interceptor chain so every tool call
	// runs the same middleware (validation, auth, tracing) as the wire RPC.
	if cfg.UnaryInterceptor != nil {
		opts = append(opts, runtime.WithUnaryInterceptor(cfg.UnaryInterceptor))
	}

	return runtime.StartServer(ctx, cfg, func(s *mcp.Server) {
		RegisterPropertyServiceMCPHandler(s, srv, opts...)
	})
}

